#[repr(C)]
#[derive(Copy, Clone)]
pub union filament_backend_ConstantValue {
    pub i: i32,
    pub f: f32,
    pub b: bool,
}
impl Default for filament_backend_ConstantValue {
    fn default() -> Self {
        let mut s = ::core::mem::MaybeUninit::<Self>::uninit();
        unsafe {
            ::core::ptr::write_bytes(s.as_mut_ptr(), 0, 1);
            s.assume_init()
        }
    }
}
