pub type filament_View_VsmShadowOptions = filament_VsmShadowOptions;
#[doc = " View-level options for DPCF and PCSS Shadowing.\n @see #setSoftShadowOptions\n <b>Warning:</b> This API is still experimental and subject to change."]
pub type filament_View_SoftShadowOptions = filament_SoftShadowOptions;
#[doc = " Options for Screen-space Reflections.\n @see #setScreenSpaceReflectionsOptions"]
